#!/bin/sh
# Auto-generated POSIX shell benchmark -- do not edit by hand.
# Generated by scripts/gen_bench.py.
#
# Usage:
#   $SHELL scripts/bench.sh                    # run every section
#   $SHELL scripts/bench.sh NAME               # run a single section
#   $SHELL scripts/bench.sh NAME LOCALE        # run NAME under a specific
#                                              #   locale (locale-sensitive
#                                              #   sections only)
#   $SHELL scripts/bench.sh --list             # list available section names
#   $SHELL scripts/bench.sh --help             # show this help
#
# The single-section form is intended for profiling (e.g.
# `perf record -- target/release/meiksh scripts/bench.sh arith_int`): it
# skips banners/totals and emits only the one timed row.
#
# Each section targets ~10s on release meiksh. Locale-sensitive sections
# (Category B) run once per available locale (C, C.UTF-8, en_US.UTF-8 if
# present); the rest run once. Per-section setup (mkdir, file population,
# long-string initialisation) runs via a *_setup helper that is NOT
# included in the timed section; fixtures are cleaned up in bulk by the
# EXIT trap when the benchmark finishes.

set -e

BENCH_DIR=$(mktemp -d)
trap 'rm -rf "$BENCH_DIR"' EXIT

# Helper: print a second-precision duration for running "$@".
section_time() {
    _label=$1; shift
    _start=$(date +%s)
    "$@"
    _end=$(date +%s)
    printf "    %-42s %ss\n" "$_label" "$(( _end - _start ))"
}

# Helper: run a bench with its setup (if defined) before timing.
run_bench() {
    _rb_label=$1
    _rb_fn=$2
    if command -v "${_rb_fn}_setup" >/dev/null 2>&1; then
        "${_rb_fn}_setup"
    fi
    section_time "$_rb_label" "$_rb_fn"
}

print_header() {
    printf "\n-- %s --\n" "$1"
}

print_sub_header() {
    printf "  -- locale: %s --\n" "$1"
}

# Probe the host for the locales we want to exercise. Aliases (C.UTF-8 vs
# C.utf8, en_US.UTF-8 vs en_US.utf8) are de-duplicated: the first spelling
# that loads wins. Falls back to C if nothing else works.
detect_locales() {
    BENCH_LOCALES=''
    _have_cutf8=0
    _have_enus=0
    for _cand in C C.UTF-8 C.utf8 en_US.UTF-8 en_US.utf8; do
        case $_cand in
            C.UTF-8|C.utf8)
                if [ $_have_cutf8 -eq 1 ]; then continue; fi ;;
            en_US.UTF-8|en_US.utf8)
                if [ $_have_enus  -eq 1 ]; then continue; fi ;;
        esac
        if ( LC_ALL=$_cand /bin/sh -c ':' ) 2>/dev/null; then
            BENCH_LOCALES="$BENCH_LOCALES $_cand"
            case $_cand in
                C.UTF-8|C.utf8)         _have_cutf8=1 ;;
                en_US.UTF-8|en_US.utf8) _have_enus=1  ;;
            esac
        fi
    done
    [ -n "$BENCH_LOCALES" ] || BENCH_LOCALES=C
}

detect_locales

_fn_noop() {
    :
}

_fn_many_args() {
    _a=$1; _b=$2; _c=$3; _d=$4; _e=$5
    _FN_RESULT=$(( _a + _b + _c + _d + _e ))
}

bench_arith_int() {
  i=0
  while [ $i -lt 1800000 ]; do
    a=$(( i + 137 ))
    b=$(( a * 7 ))
    c=$(( b - 42 ))
    d=$(( c / 5 ))
    e=$(( d % 97 ))
    f=$(( a + b + c + d + e ))
    g=$(( f / 11 + 1 ))
    h=$(( g * g ))
    k=$(( h - i ))
    m=$(( k + 2 * i ))
    : "$a" "$b" "$c" "$d" "$e" "$f" "$g" "$h" "$k" "$m"
    i=$(( i + 1 ))
  done
}

bench_arith_wide() {
  i=0
  while [ $i -lt 1500000 ]; do
    a=$(( i << 20 ))
    b=$(( a >> 3 ))
    c=$(( a & 0xFFFFF ))
    d=$(( a | 0x1000 ))
    e=$(( c ^ d ))
    f=$(( ~e ))
    g=$(( a > 1000000 ? a - 1000000 : a + 1000000 ))
    h=$(( a != 0 && b != 0 ? 1 : 0 ))
    k=$(( g * 3 + e ))
    m=$(( -a + h ))
    : "$a" "$b" "$c" "$d" "$e" "$f" "$g" "$h" "$k" "$m"
    i=$(( i + 1 ))
  done
}

bench_var_assign() {
  i=0
  while [ $i -lt 2500000 ]; do
    v1=foo
    v2=bar
    v3=baz
    v4="a little longer value with spaces"
    export V_EXPORTED=$v1
    unset V_EXPORTED
    unset v3
    v3=reborn
    : "$v1" "$v2" "$v3" "$v4"
    i=$(( i + 1 ))
  done
}

bench_builtin_dispatch() {
  i=0
  while [ $i -lt 3300000 ]; do
    :
    true
    false || :
    [ x = x ]
    test -n x
    [ $i -ge 0 ]
    i=$(( i + 1 ))
  done
}

bench_func_call() {
  i=0
  while [ $i -lt 1600000 ]; do
    _fn_noop
    _fn_noop
    _fn_many_args $i 1 2 3 4
    _fn_many_args 5 6 7 8 $i
    : "$_FN_RESULT"
    i=$(( i + 1 ))
  done
}

bench_control_flow() {
  i=0
  while [ $i -lt 1400000 ]; do
    r=0
    if [ $i -gt 0 ]; then
      if [ $i -lt 1000000000 ]; then
        if [ $(( i % 2 )) -eq 0 ]; then
          r=1
        else
          r=2
        fi
      else
        r=3
      fi
    else
      r=4
    fi
    case $(( i % 5 )) in
      0) t=alpha ;;
      1) t=bravo ;;
      2) t=charlie ;;
      3) t=delta ;;
      *) t=echo ;;
    esac
    [ $r -gt 0 ] && r=$(( r + 1 )) || r=0
    [ $r -ge 0 ] && r=$(( r + 1 )) || r=0
    [ $r -ne 99 ] && r=$(( r * 2 )) || :
    : "$r" "$t"
    i=$(( i + 1 ))
  done
}

bench_deep_parse() {
  _src='
  x=1
  if [ $x -eq 1 ]; then
    if [ $x -gt 0 ]; then
      if [ $x -lt 100 ]; then
        if [ $x -ne 99 ]; then
          x=$(( x + 1 ))
        fi
      fi
    fi
  fi
  case $x in
    1) r=one ;;
    2) r=two ;;
    3) r=three ;;
    4) r=four ;;
    5) r=five ;;
    *) r=other ;;
  esac
  [ $x -ge 0 ] && : || :
  [ -n "$r" ] && : || :
  '
  i=0
  while [ $i -lt 550000 ]; do
    eval "$_src"
    i=$(( i + 1 ))
  done
}

bench_trap_set_unset() {
  i=0
  while [ $i -lt 2700000 ]; do
    trap ':' USR1
    trap ':' USR2
    trap - USR1
    trap - USR2
    i=$(( i + 1 ))
  done
}

bench_param_trim_ascii() {
  short='foo.bar.baz.qux.txt'
  longp='the-quick-brown-fox-jumps-over-the-lazy-dog/path/to/some/nested/file.tar.gz'
  i=0
  while [ $i -lt 650000 ]; do
    a=${short%.*}
    b=${short%%.*}
    c=${short#*.}
    d=${short##*.}
    e=${longp#*/}
    f=${longp##*/}
    g=${longp%/*}
    h=${longp%%/*}
    j=${longp%.tar.gz}
    k=${longp##*-}
    : "$a" "$b" "$c" "$d" "$e" "$f" "$g" "$h" "$j" "$k"
    i=$(( i + 1 ))
  done
}

bench_param_trim_utf8() {
  short='café.ünîcôdé.δοκιμή.テスト.tar.gz'
  longp='café-δοκιμή-テスト-тест/chemin/vers/dossier/ファイル.tar.gz'
  i=0
  while [ $i -lt 650000 ]; do
    a=${short%.*}
    b=${short%%.*}
    c=${short#*.}
    d=${short##*.}
    e=${longp#*/}
    f=${longp##*/}
    g=${longp%/*}
    h=${longp%%/*}
    j=${longp%.tar.gz}
    k=${longp##*-}
    : "$a" "$b" "$c" "$d" "$e" "$f" "$g" "$h" "$j" "$k"
    i=$(( i + 1 ))
  done
}

bench_param_class_bracket() {
  v1='abc123xyz'
  v2='hello-world-42'
  v3='δοκιμή123'
  i=0
  while [ $i -lt 1800000 ]; do
    a=${v1#[[:alpha:]]}
    b=${v1##[[:alpha:]]*}
    c=${v1%[0-9]}
    d=${v1%%[0-9]*}
    e=${v2#*-}
    f=${v2%[a-z]*}
    g=${v3#[[:alpha:]]*}
    h=${v3%[[:digit:]]*}
    : "$a" "$b" "$c" "$d" "$e" "$f" "$g" "$h"
    i=$(( i + 1 ))
  done
}

bench_param_length() {
  ascii='the-quick-brown-fox-jumps-over-the-lazy-dog'
  utf8='café-δοκιμή-テスト-тест-ünîcôdé'
  empty=''
  i=0
  while [ $i -lt 3300000 ]; do
    a=${#ascii}
    b=${#utf8}
    c=${#empty}
    d=${#ascii}
    e=${#utf8}
    : "$a" "$b" "$c" "$d" "$e"
    i=$(( i + 1 ))
  done
}

bench_field_split() {
  colon='alpha:bravo:charlie:delta:echo:foxtrot:golf:hotel'
  ws='aa bb cc dd ee ff gg hh ii jj kk ll mm nn oo pp'
  mixed='one,two;three four;five,six;seven'
  utf8list='café bravo δοκιμή テスト тест'
  i=0
  while [ $i -lt 1300000 ]; do
    _old=$IFS
    IFS=:
    set -- $colon
    c1=$#
    IFS=' '
    set -- $ws
    c2=$#
    IFS=' ,;'
    set -- $mixed
    c3=$#
    IFS=' '
    set -- $utf8list
    c4=$#
    IFS=$_old
    : "$c1" "$c2" "$c3" "$c4"
    i=$(( i + 1 ))
  done
}

bench_case_utf8_patterns() {
  i=0
  while [ $i -lt 3300000 ]; do
    case $(( i % 5 )) in
      0) v=café ;;
      1) v=δοκιμή ;;
      2) v=テスト ;;
      3) v=тест ;;
      *) v=abc123 ;;
    esac
    case $v in
      'café') r=1 ;;
      'δοκιμή') r=2 ;;
      'テスト') r=3 ;;
      'тест') r=4 ;;
      [[:digit:]]*|*[[:digit:]]) r=5 ;;
      [[:alpha:]]*) r=6 ;;
      *) r=0 ;;
    esac
    case $v in
      *?*?*?*) s=long ;;
      *?*) s=multi ;;
      *) s=short ;;
    esac
    : "$r" "$s"
    i=$(( i + 1 ))
  done
}

bench_glob_class_setup() {
  if [ -d "$BENCH_DIR/glob" ]; then return; fi
  mkdir -p "$BENCH_DIR/glob"
  _j=0
  while [ $_j -lt 500 ]; do
    : > "$BENCH_DIR/glob/file_$_j.txt"
    : > "$BENCH_DIR/glob/data_$_j.dat"
    : > "$BENCH_DIR/glob/log_$_j.log"
    _j=$(( _j + 1 ))
  done
}

bench_glob_class() {
  i=0
  while [ $i -lt 7000 ]; do
    set -- "$BENCH_DIR/glob"/*.txt         ; c1=$#
    set -- "$BENCH_DIR/glob"/*.dat         ; c2=$#
    set -- "$BENCH_DIR/glob"/*_[0-9].txt   ; c3=$#
    set -- "$BENCH_DIR/glob"/file_1??.txt  ; c4=$#
    set -- "$BENCH_DIR/glob"/[[:alpha:]]*.log ; c5=$#
    : "$c1" "$c2" "$c3" "$c4" "$c5"
    i=$(( i + 1 ))
  done
}

bench_fs_create_delete() {
  i=0
  while [ $i -lt 7000 ]; do
    mkdir "$BENCH_DIR/fs_$i"
    _j=0
    while [ $_j -lt 20 ]; do
      : > "$BENCH_DIR/fs_$i/f_$_j"
      _j=$(( _j + 1 ))
    done
    rm -rf "$BENCH_DIR/fs_$i"
    i=$(( i + 1 ))
  done
}

bench_fs_read_loop_setup() {
  _f="$BENCH_DIR/read_loop.txt"
  if [ -s "$_f" ]; then return; fi
  _j=0
  while [ $_j -lt 500 ]; do
    printf 'line %d alpha bravo charlie delta echo foxtrot\n' $_j >> "$_f"
    _j=$(( _j + 1 ))
  done
}

bench_fs_read_loop() {
  _f="$BENCH_DIR/read_loop.txt"
  i=0
  while [ $i -lt 2200 ]; do
    _count=0
    while IFS= read -r _line; do
      _count=$(( _count + 1 ))
    done < "$_f"
    : "$_count"
    i=$(( i + 1 ))
  done
}

bench_io_write_append() {
  _f="$BENCH_DIR/io_append.txt"
  : > "$_f"
  i=0
  while [ $i -lt 3300000 ]; do
    echo "line $i foo bar baz quux alpha bravo charlie delta" >> "$_f"
    i=$(( i + 1 ))
  done
}

bench_io_heredoc() {
  _f="$BENCH_DIR/io_heredoc.txt"
  : > "$_f"
  _count=42
  i=0
  while [ $i -lt 15000 ]; do
    cat >> "$_f" <<HEREDOC_END
Line $i: the quick brown fox jumps over the lazy dog
Expansion: arith=$(( i * 2 + 1 )) count=$_count
More text with "quotes" and special chars.
HEREDOC_END
    i=$(( i + 1 ))
  done
}

bench_io_fd_redir() {
  _f="$BENCH_DIR/io_fd.txt"
  : > "$_f"
  i=0
  while [ $i -lt 2000000 ]; do
    echo "fd line $i" 3>"$_f" >&3
    i=$(( i + 1 ))
  done
}

bench_subshell_parens() {
  i=0
  while [ $i -lt 19000 ]; do
    ( _x=$i; : "$_x" )
    ( _y=$(( i + 1 )); : "$_y" )
    i=$(( i + 1 ))
  done
}

bench_cmd_sub_short() {
  i=0
  while [ $i -lt 17000 ]; do
    a=$(echo small)
    b=$(printf '%d' $i)
    : "$a" "$b"
    i=$(( i + 1 ))
  done
}

bench_cmd_sub_long_setup() {
  _f="$BENCH_DIR/cmd_sub_long.txt"
  if [ -s "$_f" ]; then return; fi
  _j=0
  while [ $_j -lt 200 ]; do
    printf 'long line %d with some content padding text for size\n' $_j >> "$_f"
    _j=$(( _j + 1 ))
  done
}

bench_cmd_sub_long() {
  _f="$BENCH_DIR/cmd_sub_long.txt"
  i=0
  while [ $i -lt 9000 ]; do
    x=$(cat "$_f")
    : "$x"
    i=$(( i + 1 ))
  done
}

bench_pipeline() {
  i=0
  while [ $i -lt 6000 ]; do
    echo "data $i" | cat > /dev/null
    echo "data $i" | cat | cat | cat > /dev/null
    i=$(( i + 1 ))
  done
}

bench_combined_realistic() {
  template='deployment-app-v1.2.3-20240315-release-candidate'
  i=0
  while [ $i -lt 27000 ]; do
    _name=${template#*-}
    _name=${_name%%-*}
    _version=${template##*-v}
    _version=${_version%%-*}
    _count=$(( i * 31 + ${#template} ))
    case $(( i % 3 )) in
      0) _action=build ;;
      1) _action=test ;;
      *) _action=deploy ;;
    esac
    _id=$(echo "$_action-$i")
    echo "$_id $_name $_version $_count" > /dev/null
    : "$_action"
    i=$(( i + 1 ))
  done
}

PURE_SECTIONS="arith_int arith_wide var_assign builtin_dispatch func_call control_flow deep_parse trap_set_unset"
LOCALE_SECTIONS="param_trim_ascii param_trim_utf8 param_class_bracket param_length field_split case_utf8_patterns glob_class"
IO_SECTIONS="fs_create_delete fs_read_loop io_write_append io_heredoc io_fd_redir subshell_parens cmd_sub_short cmd_sub_long pipeline"
COMBINED_SECTIONS="combined_realistic"

usage() {
    cat <<EOF
Usage:
  $0                    run every section
  $0 NAME               run a single section (profile-friendly: no banner / no TOTAL)
  $0 NAME LOCALE        run a locale-sensitive section under a specific locale
  $0 --list | -l        list available section names
  $0 --help | -h        show this help
EOF
}

list_sections() {
    printf "Pure compute:\n  %s\n"       "$PURE_SECTIONS"
    printf "Locale-sensitive:\n  %s\n"   "$LOCALE_SECTIONS"
    printf "  (detected locales:%s)\n"    "$BENCH_LOCALES"
    printf "System I/O:\n  %s\n"         "$IO_SECTIONS"
    printf "Combined:\n  %s\n"           "$COMBINED_SECTIONS"
}

# True iff $1 appears as a space-separated token in $2.
_in_list() {
    case " $2 " in *" $1 "*) return 0 ;; esac
    return 1
}

# Set LC_ALL/LANG to a specific locale (no save -- caller controls that).
_set_locale() {
    LC_ALL=$1; export LC_ALL
    LANG=$1;   export LANG
}

_save_locale() {
    _saved_lc_all_was_set=${LC_ALL+1}; _saved_lc_all=${LC_ALL-}
    _saved_lang_was_set=${LANG+1};     _saved_lang=${LANG-}
}

_restore_locale() {
    if [ "$_saved_lc_all_was_set" = 1 ]; then
        LC_ALL=$_saved_lc_all; export LC_ALL
    else
        unset LC_ALL
    fi
    if [ "$_saved_lang_was_set" = 1 ]; then
        LANG=$_saved_lang; export LANG
    else
        unset LANG
    fi
}

# Run a single named section. If the section is locale-sensitive and
# $2 is non-empty, run it only under that locale; otherwise sweep all
# detected locales. No banners, no TOTAL -- intended for profiling.
run_one() {
    _one_name=$1
    _one_loc=${2:-}
    _one_kind=
    if _in_list "$_one_name" "$PURE_SECTIONS"; then
        _one_kind=simple
    elif _in_list "$_one_name" "$IO_SECTIONS"; then
        _one_kind=simple
    elif _in_list "$_one_name" "$COMBINED_SECTIONS"; then
        _one_kind=simple
    elif _in_list "$_one_name" "$LOCALE_SECTIONS"; then
        _one_kind=locale
    fi
    case $_one_kind in
        simple)
            if [ -n "$_one_loc" ]; then
                printf "bench.sh: section %s is not locale-sensitive; ignoring LOCALE\n" "$_one_name" >&2
            fi
            run_bench "$_one_name" "bench_$_one_name"
            ;;
        locale)
            _save_locale
            if [ -n "$_one_loc" ]; then
                _set_locale "$_one_loc"
                run_bench "$_one_name" "bench_$_one_name"
            else
                for _loc in $BENCH_LOCALES; do
                    _set_locale "$_loc"
                    print_sub_header "$_loc"
                    run_bench "$_one_name" "bench_$_one_name"
                done
            fi
            _restore_locale
            ;;
        *)
            printf "bench.sh: unknown section: %s\n" "$_one_name" >&2
            printf "Use --list to see available sections.\n" >&2
            exit 2
            ;;
    esac
}

run_all() {
    printf "=== meiksh benchmark ===\n"
    printf "  locales:%s\n" "$BENCH_LOCALES"
    BENCH_START=$(date +%s)

    print_header "Pure compute"
    run_bench "arith_int" "bench_arith_int"
    run_bench "arith_wide" "bench_arith_wide"
    run_bench "var_assign" "bench_var_assign"
    run_bench "builtin_dispatch" "bench_builtin_dispatch"
    run_bench "func_call" "bench_func_call"
    run_bench "control_flow" "bench_control_flow"
    run_bench "deep_parse" "bench_deep_parse"
    run_bench "trap_set_unset" "bench_trap_set_unset"

    print_header "Locale-sensitive"
    _save_locale
    for _loc in $BENCH_LOCALES; do
        _set_locale "$_loc"
        print_sub_header "$_loc"
        run_bench "param_trim_ascii" "bench_param_trim_ascii"
        run_bench "param_trim_utf8" "bench_param_trim_utf8"
        run_bench "param_class_bracket" "bench_param_class_bracket"
        run_bench "param_length" "bench_param_length"
        run_bench "field_split" "bench_field_split"
        run_bench "case_utf8_patterns" "bench_case_utf8_patterns"
        run_bench "glob_class" "bench_glob_class"
    done
    _restore_locale

    print_header "System I/O"
    run_bench "fs_create_delete" "bench_fs_create_delete"
    run_bench "fs_read_loop" "bench_fs_read_loop"
    run_bench "io_write_append" "bench_io_write_append"
    run_bench "io_heredoc" "bench_io_heredoc"
    run_bench "io_fd_redir" "bench_io_fd_redir"
    run_bench "subshell_parens" "bench_subshell_parens"
    run_bench "cmd_sub_short" "bench_cmd_sub_short"
    run_bench "cmd_sub_long" "bench_cmd_sub_long"
    run_bench "pipeline" "bench_pipeline"

    print_header "Combined"
    run_bench "combined_realistic" "bench_combined_realistic"

    BENCH_END=$(date +%s)
    printf "\n  TOTAL: %ss\n" "$(( BENCH_END - BENCH_START ))"
}

case ${1:-} in
    --help|-h)  usage; exit 0 ;;
    --list|-l)  list_sections; exit 0 ;;
    "")         run_all ;;
    -*)         usage >&2; exit 2 ;;
    *)          run_one "$1" "${2:-}" ;;
esac

